import React from "react";
import styles from "./UserProfile.module.css";

interface UserProfileProps {
  userName: string;
  onLogout?: () => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ userName, onLogout }) => {
  return (
    <div className={styles.userProfile} onClick={onLogout}>
      <div className={styles.profileIcon}>
        <img src={`${process.env.PUBLIC_URL}/images/prof.svg`} alt="Profile" />
      </div>
      <span className={styles.profileData}>{userName}</span>
      <div className={styles.arrowIcon} />
    </div>
  );
};

export default UserProfile;
